import React from 'react';

const Introduction = () => {
  return (
    <section
      id="Introduction"
      className="min-h-screen flex items-center px-5 pt-24"
      style={{
        background:
          'linear-gradient(rgba(0,5,43,0.75), rgba(0,5,43,0.90)), url(/images/background-image.jpg) no-repeat center center / cover',
      }}
    >
      {/* Floating PS symbols — decorative */}
      <span
        aria-hidden="true"
        style={{
          position: 'absolute',
          top: '15%',
          right: '8%',
          fontSize: '96px',
          opacity: 0.04,
          fontFamily: 'sans-serif',
          userSelect: 'none',
          lineHeight: 1,
          color: '#fff',
        }}
      >
        ✕{'\n'}○{'\n'}□{'\n'}△
      </span>

      <div className="flex flex-col md:flex-row items-center justify-between w-full max-w-5xl mx-auto gap-12">
        <div className="flex-1">
          {/* PS-style top label */}
          <p
            className="text-xs font-bold mb-3 tracking-widest"
            style={{ color: '#7fc5e8', letterSpacing: '4px' }}
          >
            ✕ PLAYER ONE
          </p>

          <h1 className="intro-name font-bold text-white">ALIHAKIM M. DIMACALING</h1>

          <p className="italic text-lg text-white mt-3" style={{ color: '#c5d8f0' }}>
            University Student&nbsp;|&nbsp;Game Enthusiast&nbsp;|&nbsp;Aspiring IT Professional
          </p>

          <p className="text-white mt-4 text-base" style={{ color: 'rgba(255,255,255,0.75)' }}>
            Hi! I am currently pursuing a Bachelor's Degree in Information Technology majoring in Web Technology.
          </p>

          {/* PS button row */}
          <div className="flex gap-4 mt-6">
            {[
              { sym: '✕', label: 'Projects', color: '#7fc5e8', href: '#Projects' },
              { sym: '○', label: 'Contact',  color: '#e87b7b', href: '#Contact'  },
            ].map(({ sym, label, color, href }) => (
              <a
                key={label}
                href={href}
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '6px',
                  padding: '8px 18px',
                  borderRadius: '6px',
                  border: `1px solid ${color}`,
                  color: '#ffffff',
                  fontSize: '13px',
                  fontFamily: 'inherit',
                  textDecoration: 'none',
                  transition: 'background 0.2s',
                }}
                onMouseEnter={e => (e.currentTarget.style.background = `${color}22`)}
                onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
              >
                <span style={{ color, fontSize: '12px' }}>{sym}</span>
                {label}
              </a>
            ))}
          </div>
        </div>

        <div className="flex justify-center">
          <div style={{ position: 'relative' }}>
            {/* Glowing ring */}
            <div
              style={{
                position: 'absolute',
                inset: '-8px',
                borderRadius: '50%',
                border: '2px solid rgba(0,112,204,0.5)',
                boxShadow: '0 0 24px rgba(0,112,204,0.4)',
              }}
            />
            <img
              src="/images/portrait-image.png"
              alt="Portrait"
              className="rounded-full object-cover"
              style={{ width: '250px', height: '250px', border: '4px solid #003791' }}
            />
          </div>
        </div>
      </div>
    </section>
  );
};

export default Introduction;
